graphql.query:
query GetOrderWithJoins($id: ID!) {
  order(id: $id) {
    id
    status
    total_amount
    customer_name
    delivery_address
    items { product_name quantity unit_price }
    driver {
      id
      name
      vehicle_type
      status
      last_location { latitude longitude timestamp }
    }
    delivery {
      id
      status
      driver_name
      history {
        event_type
        created_at
      }
    }
  }
}

query ListOrders($customer_id: String, $status: String, $limit: Int) {
  orders(customer_id: $customer_id, status: $status, limit: $limit) {
    total
    orders {
      id
      status
      customer_name
      total_amount
      created_at
    }
  }
}

query GetDriver($id: ID!) {
  driver(id: $id) {
    id
    name
    phone
    vehicle_type
    status
    current_order_id
    last_location { latitude longitude speed_kmh heading_deg timestamp }
    current_order {
      id
      status
      customer_name
      delivery_address
    }
  }
}

query AvailableDrivers($limit: Int) {
  availableDrivers(limit: $limit) {
    total
    drivers {
      id
      name
      vehicle_type
      last_location { latitude longitude }
    }
  }
}

query GetDelivery($id: ID!) {
  delivery(id: $id) {
    id
    status
    driver_name
    delivery_address
    order { id status customer_name total_amount }
    driver { id name vehicle_type status }
    history { event_type created_at event_data_json }
  }
}

query InTransitDeliveries {
  deliveries(status: "IN_TRANSIT", limit: 20) {
    total
    deliveries {
      id
      delivery_address
      driver {
        id
        name
        last_location { latitude longitude }
      }
      order {
        customer_name
        total_amount
      }
    }
  }
}

query AllDeliveriesWithHistory {
  deliveries(limit: 5) {
    total
    deliveries {
      id
      status
      driver_name
      history { event_type created_at }
    }
  }
}

query DeliveryByOrder($order_id: ID!) {
  deliveryByOrder(order_id: $order_id) {
    id
    status
    driver_name
    delivery_address
    history { event_type created_at }
  }
}

mutation CreateOrder($input: CreateOrderInput!) {
  createOrder(input: $input) {
    id
    status
    total_amount
    customer_name
    items { product_name quantity unit_price }
  }
}

mutation CancelOrder($id: ID!, $reason: String) {
  cancelOrder(id: $id, reason: $reason) {
    id
    status
    updated_at
  }
}

mutation RegisterDriver($input: RegisterDriverInput!) {
  registerDriver(input: $input) {
    id
    name
    phone
    vehicle_type
    status
    created_at
  }
}

mutation UpdateLocation($input: UpdateLocationInput!) {
  updateDriverLocation(input: $input) {
    driver_id
    latitude
    longitude
    speed_kmh
    heading_deg
    timestamp
  }
}

mutation AdvanceDelivery($id: ID!, $newStatus: String!) {
  advanceDelivery(delivery_id: $id, new_status: $newStatus) {
    id
    status
    driver_name
    order {
      id
      status
    }
  }
}
